package org.apache.commons.math3.linear;

import org.apache.commons.math3.util.FastMath;

/**
 * Calculates the rectangular Cholesky decomposition of a matrix.
 * <p>The rectangular Cholesky decomposition of a real symmetric positive
 * semidefinite matrix A consists of a rectangular matrix B with the same
 * number of rows such that: A is almost equal to BB<sup>T</sup>, depending
 * on a user-defined tolerance. In a sense, this is the square root of A.</p>
 * <p>The difference with respect to the regular {@link CholeskyDecomposition}
 * is that rows/columns may be permuted (hence the rectangular shape instead
 * of the traditional triangular shape) and there is a threshold to ignore
 * small diagonal elements. This is used for example to generate {@link
 * org.apache.commons.math3.random.CorrelatedRandomVectorGenerator correlated
 * random n-dimensions vectors} in a p-dimension subspace (p < n).
 * In other words, it allows generating random vectors from a covariance
 * matrix that is only positive semidefinite, and not positive definite.</p>
 * <p>Rectangular Cholesky decomposition is <em>not</em> suited for solving
 * linear systems, so it does not provide any {@link DecompositionSolver
 * decomposition solver}.</p>
 *
 * @see <a href="http://mathworld.wolfram.com/CholeskyDecomposition.html">MathWorld</a>
 * @see <a href="http://en.wikipedia.org/wiki/Cholesky_decomposition">Wikipedia</a>
 * @version $Id$
 * @since 2.0 (changed to concrete class in 3.0)
 */
public class RectangularCholeskyDecomposition {

    /** Permutated Cholesky root of the symmetric positive semidefinite matrix. */
    private final RealMatrix root;

    /** Rank of the symmetric positive semidefinite matrix. */
    private int rank;

    /**
     * Decompose a symmetric positive semidefinite matrix.
     *
     * @param matrix Symmetric positive semidefinite matrix.
     * @param small Diagonal elements threshold under which  column are
     * considered to be dependent on previous ones and are discarded.
     * @exception NonPositiveDefiniteMatrixException if the matrix is not
     * positive semidefinite.
     */
    public RectangularCholeskyDecomposition(RealMatrix matrix, double small)
        throws NonPositiveDefiniteMatrixException {

        final int order = matrix.getRowDimension();
        final double[][] c = matrix.getData();
        final double[][] b = new double[order][order];

        int[] swap  = new int[order];
        int[] index = new int[order];
        for (int i = 0; i < order; ++i) {
            index[i] = i;
        }

        int r = 0;
        for (boolean loop = true; loop;) {

            // find maximal diagonal element
            swap[r] = r;
            for (int i = r + 1; i < order; ++i) {
                int ii  = index[i];
                int isi = index[swap[i]];
                if (c[ii][ii] > c[isi][isi]) {
                    swap[r] = i;
                }
            }


            // swap elements
            if (swap[r] != r) {
                int tmp = index[r];
                index[r] = index[swap[r]];
                index[swap[r]] = tmp;
            }

            // check diagonal element
            int ir = index[r];
            if (c[ir][ir] < small) {

                if (r == 0) {
                    throw new NonPositiveDefiniteMatrixException(c[ir][ir], ir, small);
                }

                // check remaining diagonal elements
                for (int i = r; i < order; ++i) {
                    if (c[index[i]][index[i]] < -small) {
                        // there is at least one sufficiently negative diagonal element,
                        // the symmetric positive semidefinite matrix is wrong
                        throw new NonPositiveDefiniteMatrixException(c[index[i]][index[i]], i, small);
                    }
                }

                // all remaining diagonal elements are close to zero, we consider we have
                // found the rank of the symmetric positive semidefinite matrix
                ++r;
                loop = false;

            } else {

                // transform the matrix
                final double sqrt = FastMath.sqrt(c[ir][ir]);
                b[r][r] = sqrt;
                final double inverse  = 1 / sqrt;
                for (int i = r + 1; i < order; ++i) {
                    final int ii = index[i];
                    final double e = inverse * c[ii][ir];
                    b[i][r] = e;
                    c[ii][ii] -= e * e;
                    for (int j = r + 1; j < i; ++j) {
                        final int ij = index[j];
                        final double f = c[ii][ij] - e * b[j][r];
                        c[ii][ij] = f;
                        c[ij][ii] = f;
                    }
                }

                // prepare next iteration
                loop = ++r < order;
            }
        }

        // build the root matrix
        rank = r;
        root = MatrixUtils.createRealMatrix(order, r);
        for (int i = 0; i < order; ++i) {
            for (int j = 0; j < r; ++j) {
                root.setEntry(index[i], j, b[i][j]);
            }
        }

    }

    /** Get the root of the covariance matrix.
     * The root is the rectangular matrix <code>B</code> such that
     * the covariance matrix is equal to <code>B.B<sup>T</sup></code>
     * @return root of the square matrix
     * @see #getRank()
     */
    public RealMatrix getRootMatrix() {
        return root;
    }

    /** Get the rank of the symmetric positive semidefinite matrix.
     * The r is the number of independent rows in the symmetric positive semidefinite
     * matrix, it is also the number of columns of the rectangular
     * matrix of the decomposition.
     * @return r of the square matrix.
     * @see #getRootMatrix()
     */
    public int getRank() {
        return rank;
    }

}

package org.apache.commons.math3.linear.steps;

import cucumber.api.java.en.Given;
import cucumber.api.java.en.When;
import cucumber.api.java.en.Then;
import org.apache.commons.math3.linear.*;
import org.apache.commons.math3.exception.MathIllegalArgumentException;
import org.apache.commons.math3.exception.NullArgumentException;
import org.apache.commons.math3.exception.DimensionMismatchException;

import java.util.Arrays;

import static org.junit.Assert.*;

public class StepDefs {

    private RealMatrix matrix;
    private RectangularCholeskyDecomposition decomposition;
    private double[][] matrixData;

    @Given("^a (\\d+)x(\\d+) symmetric positive semidefinite matrix \"([^\"]*)\" defined as:$")
    public void a_symmetric_positive_semidefinite_matrix_defined_as(int rows, int cols, String matrixName, java.util.List<java.util.List<String>> table) {
        matrixData = new double[rows][cols];
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                matrixData[i][j] = Double.parseDouble(table.get(i).get(j));
            }
        }

        // Create the matrix
        matrix = new Array2DRowRealMatrix(matrixData);
    }

    @When("^I perform a Rectangular Cholesky Decomposition on \"([^\"]*)\" with a threshold of ([\\d\\.e\\-+]+)$")
    public void i_perform_a_Rectangular_Cholesky_Decomposition_on_with_a_threshold_of(String matrixName, double threshold) {
        try {
            decomposition = new RectangularCholeskyDecomposition(matrix, threshold);
        } catch (Exception e) {
            // Capture any exception during decomposition for the bug case
            throw new RuntimeException("Error during decomposition: " + e.getMessage(), e);
        }
    }

    @Then("^the rebuilt matrix from the decomposition should match \"([^\"]*)\" within a tolerance of ([\\d\\.e\\-+]+)$")
    public void the_rebuilt_matrix_from_the_decomposition_should_match_within_a_tolerance_of(String matrixName, double tolerance) {
        assertTrue("Decomposition should not be null", decomposition != null);

        // Get the root matrix from the decomposition (this is the buggy version)
        RealMatrix rootMatrix = decomposition.getRootMatrix();

        // Compute Root * Root^T to rebuild the original matrix
        RealMatrix rebuiltMatrix = rootMatrix.multiply(rootMatrix.transpose());

        // Compare with original matrix
        RealMatrix originalMatrix = matrix;

        for (int i = 0; i < originalMatrix.getRowDimension(); i++) {
            for (int j = 0; j < originalMatrix.getColumnDimension(); j++) {
                double originalValue = originalMatrix.getEntry(i, j);
                double rebuiltValue = rebuiltMatrix.getEntry(i, j);
                assertEquals("Matrix values at [" + i + "][" + j + "] do not match",
                           originalValue, rebuiltValue, tolerance);
            }
        }
    }

    @Then("^the rank of the decomposition should be (\\d+)$")
    public void the_rank_of_the_decomposition_should_be(int expectedRank) {
        assertTrue("Decomposition should not be null", decomposition != null);
        int actualRank = decomposition.getRank();
        assertEquals("Rank mismatch", expectedRank, actualRank);
    }
}

